@@ -0,0 +1,160 @@
+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This is a stub implementation that simulates email delivery by logging
+ * the operation. The interface is real and production-ready; only the
+ * transport layer is stubbed.
+ *
+ * To integrate a real email provider:
+ * 1. Add the provider SDK to package.json dependencies.
+ * 2. Replace the send() implementation with actual API calls.
+ * 3. Update isAvailable() to check provider connectivity.
+ *
+ * Implements: NotificationAdapter (channel: 'email')
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * Configuration for the email adapter.
+ */
+export interface EmailAdapterConfig {
+  /** Sender email address (the "from" address) */
+  fromAddress: string;
+  /** Sender display name */
+  fromName: string;
+  /** Whether the adapter is enabled. When false, isAvailable() returns false. */
+  enabled: boolean;
+}
+
+/** Default email adapter configuration. */
+export const defaultEmailConfig: EmailAdapterConfig = {
+  fromAddress: 'noreply@taskflow.example.com',
+  fromName: 'TaskFlow Pro',
+  enabled: true,
+};
+
+/**
+ * Represents a composed email message ready for delivery.
+ * Used internally by the adapter to structure outgoing emails.
+ */
+export interface EmailMessage {
+  /** Sender address */
+  from: string;
+  /** Recipient address */
+  to: string;
+  /** Email subject line */
+  subject: string;
+  /** Plain text body */
+  body: string;
+  /** Priority flag for email headers */
+  priority: string;
+  /** Optional additional headers */
+  headers?: Record<string, string>;
+}
+
+export class EmailAdapter implements NotificationAdapter {
+  readonly channel = 'email' as const;
+  private logger = new Logger('EmailAdapter');
+  private config: EmailAdapterConfig;
+  private sentEmails: EmailMessage[] = [];
+
+  constructor(config?: Partial<EmailAdapterConfig>) {
+    this.config = { ...defaultEmailConfig, ...config };
+  }
+
+  /**
+   * Send an email notification.
+   *
+   * Stub implementation: composes the email message and logs it.
+   * In production, this would call an SMTP server or email API (SendGrid, SES, etc.).
+   *
+   * @param payload - The notification to deliver via email.
+   * @returns Result indicating delivery success or failure.
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    if (!this.isAvailable()) {
+      return {
+        success: false,
+        errorMessage: 'Email adapter is not available (disabled in configuration)',
+      };
+    }
+
+    try {
+      const email = this.composeEmail(payload);
+
+      // --- STUB: In production, replace this block with real email sending ---
+      this.logger.info(
+        `Email sent: to=${email.to}, subject="${email.subject}", from=${email.from}`,
+      );
+      this.sentEmails.push(email);
+      // --- END STUB ---
+
+      return {
+        success: true,
+        adapterResponse: {
+          messageId: `email-${Date.now()}`,
+          from: email.from,
+          to: email.to,
+        },
+      };
+    } catch (error) {
+      const errorMessage = error instanceof Error ? error.message : 'Unknown email delivery error';
+      this.logger.error(`Email delivery failed: ${errorMessage}`);
+      return {
+        success: false,
+        errorMessage,
+      };
+    }
+  }
+
+  /**
+   * Check if the email adapter is available for sending.
+   */
+  isAvailable(): boolean {
+    return this.config.enabled;
+  }
+
+  /**
+   * Get all emails sent by this adapter (useful for testing).
+   */
+  getSentEmails(): EmailMessage[] {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Clear the sent emails log (useful for testing).
+   */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+
+  /**
+   * Get the current configuration.
+   */
+  getConfig(): Readonly<EmailAdapterConfig> {
+    return { ...this.config };
+  }
+
+  /**
+   * Compose an EmailMessage from a NotificationPayload.
+   */
+  private composeEmail(payload: NotificationPayload): EmailMessage {
+    const email: EmailMessage = {
+      from: `${this.config.fromName} <${this.config.fromAddress}>`,
+      to: payload.recipient,
+      subject: payload.subject,
+      body: payload.body,
+      priority: payload.priority,
+    };
+
+    // Merge any adapter-specific metadata as email headers
+    if (payload.metadata) {
+      email.headers = { ...payload.metadata };
+    }
+
+    return email;
+  }
+}

