 * ARCHITECTURAL CONSTRAINT: All inter-service communication MUST go through
 * the EventBus. Services MUST NOT call each other directly for side effects.
 * All events MUST be defined here and included in the AppEvent union type.
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { Notification, NotificationType } from '../models/notification.js';

// --- Domain Events (emitted by business services) ---

export interface OrderCreatedEvent {
  type: 'order:created';
  order: Order;
