import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;

  beforeEach(() => {
    eventBus = new EventBus();
    service = new NotificationService(eventBus);
    resetNotificationIdCounter();
  });

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });
  });

  describe('order:status-changed handler (via EventBus)', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
    });
  });

  describe('notification management', () => {
    it('should count notifications', async () => {
      expect(service.getNotificationCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(service.getNotificationCount()).toBe(1);
    });

    it('should filter by recipient', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(service.getNotificationsForRecipient('alice@example.com')).toHaveLength(1);
      expect(service.getNotificationsForRecipient('bob@example.com')).toHaveLength(0);
    });

    it('should clear notifications', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      service.clearNotifications();
      expect(service.getNotificationCount()).toBe(0);
    });

    it('should generate sequential notification IDs', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-2',
          userId: 'user-1',
          items: [],
          total: 30,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const notifications = service.getNotifications();
      expect(notifications[0]?.id).toBe('notif-0001');
      expect(notifications[1]?.id).toBe('notif-0002');
    });
  });

  describe('adapter registration', () => {
    it('should register and retrieve adapters', () => {
      const emailAdapter = new EmailAdapter();
      service.registerAdapter(emailAdapter);

      expect(service.getAdapter('email')).toBe(emailAdapter);
      expect(service.getRegisteredChannels()).toContain('email');
    });

    it('should unregister adapters', () => {
      const emailAdapter = new EmailAdapter();
      service.registerAdapter(emailAdapter);

      expect(service.unregisterAdapter('email')).toBe(true);
      expect(service.getAdapter('email')).toBeUndefined();
    });

    it('should return false when unregistering non-existent adapter', () => {
      expect(service.unregisterAdapter('webhook')).toBe(false);
    });

    it('should replace existing adapter for same channel', () => {
      const adapter1 = new EmailAdapter({ fromAddress: 'a@test.com' });
      const adapter2 = new EmailAdapter({ fromAddress: 'b@test.com' });

      service.registerAdapter(adapter1);
      service.registerAdapter(adapter2);

      expect(service.getAdapter('email')).toBe(adapter2);
    });
  });

  describe('send() with adapters', () => {
    it('should send notification through adapter and record it', async () => {
      const emailAdapter = new EmailAdapter();
      service.registerAdapter(emailAdapter);

      const notification = await service.send({
        recipient: 'alice@example.com',
        subject: 'Test Subject',
        body: 'Test body content',
        channel: 'email',
        priority: 'normal',
      });

      expect(notification.status).toBe('sent');
      expect(notification.recipient).toBe('alice@example.com');
      expect(notification.sentAt).toBeDefined();
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
    });

    it('should fail gracefully when no adapter is registered', async () => {
      const notification = await service.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'webhook',
      });

      expect(notification.status).toBe('failed');
      expect(notification.errorMessage).toContain('No adapter registered');
    });

    it('should fail gracefully when adapter is unavailable', async () => {
      const emailAdapter = new EmailAdapter({ enabled: false });
      service.registerAdapter(emailAdapter);

      const notification = await service.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'email',
      });

      expect(notification.status).toBe('failed');
      expect(notification.errorMessage).toContain('not available');
    });

    it('should emit notification lifecycle events', async () => {
      const emailAdapter = new EmailAdapter();
      service.registerAdapter(emailAdapter);

      await service.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'email',
      });

      const eventLog = eventBus.getEventLog();
      const notifEvents = eventLog.filter(
        (e) => e.type === 'notification:requested' || e.type === 'notification:sent',
      );
      expect(notifEvents).toHaveLength(2);
      expect(notifEvents[0]?.type).toBe('notification:requested');
      expect(notifEvents[1]?.type).toBe('notification:sent');
    });

    it('should default priority to normal', async () => {
      const emailAdapter = new EmailAdapter();
      service.registerAdapter(emailAdapter);

      const notification = await service.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'email',
      });

      expect(notification.priority).toBe('normal');
    });
  });
});

