import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('channel', () => {
    it('should report email as its channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('isAvailable', () => {
    it('should be available by default', () => {
      expect(adapter.isAvailable()).toBe(true);
    });

    it('should be unavailable when disabled', () => {
      const disabled = new EmailAdapter({ enabled: false });
      expect(disabled.isAvailable()).toBe(false);
    });
  });

  describe('send', () => {
    const payload: NotificationPayload = {
      recipient: 'alice@example.com',
      subject: 'Test Subject',
      body: 'Test body content',
      channel: 'email',
      priority: 'normal',
    };

    it('should send an email successfully', async () => {
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.adapterResponse?.to).toBe('alice@example.com');
    });

    it('should record sent emails', async () => {
      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Test Subject');
      expect(sent[0]?.body).toBe('Test body content');
    });

    it('should compose from address from config', async () => {
      const custom = new EmailAdapter({
        fromAddress: 'custom@test.com',
        fromName: 'Custom Sender',
      });

      await custom.send(payload);

      const sent = custom.getSentEmails();
      expect(sent[0]?.from).toBe('Custom Sender <custom@test.com>');
    });

    it('should fail when adapter is disabled', async () => {
      const disabled = new EmailAdapter({ enabled: false });
      const result = await disabled.send(payload);

      expect(result.success).toBe(false);
      expect(result.errorMessage).toContain('not available');
    });

    it('should include metadata as headers', async () => {
      const payloadWithMeta: NotificationPayload = {
        ...payload,
        metadata: { 'X-Custom-Header': 'custom-value' },
      };

      await adapter.send(payloadWithMeta);

      const sent = adapter.getSentEmails();
      expect(sent[0]?.headers?.['X-Custom-Header']).toBe('custom-value');
    });
  });

  describe('management', () => {
    it('should clear sent emails', async () => {
      await adapter.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Body',
        channel: 'email',
        priority: 'normal',
      });

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });

    it('should return config', () => {
      const config = adapter.getConfig();
      expect(config.fromAddress).toBe('noreply@taskflow.example.com');
      expect(config.fromName).toBe('TaskFlow Pro');
      expect(config.enabled).toBe(true);
    });
  });
});
